// ---------------------------------------------------------------------------
// 6. Cell-by-cell exact value comparison against pandas reference Parquet
// ---------------------------------------------------------------------------
//
// These tests load each SAS7BDAT fixture with our parser and compare every
// cell value against the corresponding pandas-generated Parquet reference.
//
// ## Type normalisation performed before comparison
//
// | Our parser dtype  | Pandas Parquet dtype  | Normalisation                        |
// |-------------------|-----------------------|--------------------------------------|
// | f64               | f64                   | Bit-exact for integer floats;        |
// |                   |                       | relative epsilon 1e-10 for others    |
// | str               | str                   | Exact string match (trailing spaces  |
// |                   |                       | trimmed defensively)                 |
// | date (i32 days    | datetime[ms] midnight | our_days * 86_400_000 == pandas_ms   |
// |   since Unix)     |                       |                                      |
// | datetime[ms]      | datetime[ms]          | Direct i64 comparison                |
// | f64 (SAS days     | datetime[ms] midnight | (our_val as i64 - 3653) *            |
// |   since SAS epoch |                       |   86_400_000 == pandas_ms            |
// |   stored as float)|                       |   (3653 = days 1960-01-01→1970-01-01)|
//
// Note: LargeUtf8 in the Parquet file is read by Polars as `str` (Utf8),
// so the "both str" case handles both Utf8 and LargeUtf8 source formats.

/// Milliseconds per day.
const MS_PER_DAY: i64 = 86_400_000;

/// Day offset from SAS epoch (1960-01-01) to Unix epoch (1970-01-01).
/// Confirmed: 1970-01-01 minus 1960-01-01 = 3653 days.
const SAS_TO_UNIX_DAYS: i64 = 3653;

/// Relative epsilon used when comparing non-integer-valued f64 cells.
const F64_REL_EPS: f64 = 1e-10;

/// Extract the string payload from an `AnyValue`, normalising both the
/// borrowed (`String`) and owned (`StringOwned`) variants produced by Polars
/// depending on the backing array type.
fn anyvalue_as_str<'a>(v: &'a AnyValue<'a>) -> Option<&'a str> {
    match v {
        AnyValue::String(s) => Some(s),
        AnyValue::StringOwned(s) => Some(s.as_str()),
        _ => None,
    }
}

/// Options controlling how `compare_cell` and `compare_dataframes` judge
/// equality.
#[derive(Debug, Clone, Copy)]
struct CompareOptions {
    /// Maximum tolerated absolute difference for `Datetime[ms]` comparisons,
    /// in milliseconds.  Set to 0 for exact comparison.
    ///
    /// A non-zero tolerance is needed for the `datetime.sas7bdat` fixture
    /// whose extreme boundary values (years ~1677 and ~2262) are stored with
    /// 7-byte truncated SAS numerics.  The LSB-zeroing in the reconstructed
    /// float64 causes a 1 ms rounding difference at the i64 boundary, which
    /// is a known precision limitation of our parser, not a data error.
    datetime_tolerance_ms: i64,
}

impl CompareOptions {
    /// Exact comparison with zero tolerance for all types.
    fn exact() -> Self {
        Self {
            datetime_tolerance_ms: 0,
        }
    }

    /// Allow up to `tol` milliseconds of absolute error in Datetime cells.
    fn with_datetime_tolerance(tol: i64) -> Self {
        Self {
            datetime_tolerance_ms: tol,
        }
    }
}

/// Compare a single cell value from our SAS parser column against the
/// corresponding cell from the pandas reference column.
///
/// Returns `None` on match, or `Some(description)` on mismatch.
/// Handles: f64 vs f64 (bit-exact for integers, relative epsilon for
/// fractional), str vs str (exact, trailing space trimmed), date vs
/// datetime[ms] (days * MS_PER_DAY), datetime[ms] vs datetime[ms]
/// (direct i64), and f64-SAS-days vs datetime[ms] (subtract
/// SAS_TO_UNIX_DAYS then multiply by MS_PER_DAY).
fn compare_cell(
    our_col: &Column,
    pd_col: &Column,
    row: usize,
    col_name: &str,
    opts: CompareOptions,
) -> Option<String> {
    use AnyValue::{Date, Datetime, Float64, Null};

    let our_val = our_col.get(row).unwrap_or(Null);
    let pd_val = pd_col.get(row).unwrap_or(Null);

    // Both null was already handled by the caller; if we reach here both are
    // guaranteed non-null.

    // Check string-vs-string first (must precede the wildcard arms).
    if let (Some(a), Some(b)) = (anyvalue_as_str(&our_val), anyvalue_as_str(&pd_val)) {
        let a_trimmed: &str = a.trim_end();
        let b_trimmed: &str = b.trim_end();
        if a_trimmed != b_trimmed {
            return Some(format!(
                "col '{col_name}'[{row}] str mismatch: ours={a_trimmed:?}, \
                 pandas={b_trimmed:?}"
            ));
        }
        return None;
    }

    match (&our_val, &pd_val) {
        // ----------------------------------------------------------------
        // Float64 vs Float64
        // ----------------------------------------------------------------
        (Float64(a), Float64(b)) => {
            // For integer-valued floats compare with zero tolerance.
            if a.fract() == 0.0 && b.fract() == 0.0 {
                if a.to_bits() != b.to_bits() {
                    return Some(format!(
                        "col '{col_name}'[{row}] f64 mismatch: ours={a}, pandas={b}"
                    ));
                }
            } else {
                let denom = b.abs().max(1.0);
                let rel_err = (a - b).abs() / denom;
                if rel_err > F64_REL_EPS {
                    return Some(format!(
                        "col '{col_name}'[{row}] f64 mismatch: ours={a:.15e}, \
                         pandas={b:.15e} (rel_err={rel_err:.2e})"
                    ));
                }
            }
            None
        }

        // ----------------------------------------------------------------
        // Our Date (i32 days since Unix epoch) vs pandas Datetime[ms]
        // Pandas stores SAS date columns as timestamp[ms] at midnight UTC.
        // ----------------------------------------------------------------
        (Date(our_days), Datetime(pd_ms, _, _)) => {
            let our_ms = i64::from(*our_days) * MS_PER_DAY;
            let abs_diff = (our_ms - pd_ms).unsigned_abs();
            if abs_diff > opts.datetime_tolerance_ms as u64 {
                return Some(format!(
                    "col '{col_name}'[{row}] date vs datetime mismatch: \
                     ours={our_days} days ({our_ms} ms), pandas={pd_ms} ms \
                     (diff={abs_diff} ms)"
                ));
            }
            None
        }

        // ----------------------------------------------------------------
        // Both Datetime[ms] — i64 comparison with configurable tolerance.
        // ----------------------------------------------------------------
        (Datetime(our_ms, _, _), Datetime(pd_ms, _, _)) => {
            let abs_diff = (our_ms - pd_ms).unsigned_abs();
            if abs_diff > opts.datetime_tolerance_ms as u64 {
                return Some(format!(
                    "col '{col_name}'[{row}] datetime mismatch: ours={our_ms} ms, \
                     pandas={pd_ms} ms (diff={abs_diff} ms, tol={} ms)",
                    opts.datetime_tolerance_ms
                ));
            }
            None
        }

        // ----------------------------------------------------------------
        // Our Float64 (SAS days since SAS epoch 1960-01-01) vs pandas
        // Datetime[ms] at midnight.
        //
        // Some date-formatted columns are stored as f64 by our parser when
        // the SAS format family is not recognised as a standard date type
        // (e.g. YEAR4-family formats like the "Taiw" column).
        // ----------------------------------------------------------------
        (Float64(our_sas_days), Datetime(pd_ms, _, _)) => {
            let our_ms = ((*our_sas_days as i64) - SAS_TO_UNIX_DAYS) * MS_PER_DAY;
            let abs_diff = (our_ms - pd_ms).unsigned_abs();
            if abs_diff > opts.datetime_tolerance_ms as u64 {
                return Some(format!(
                    "col '{col_name}'[{row}] f64-date vs datetime mismatch: \
                     ours={our_sas_days} SAS days ({our_ms} ms), pandas={pd_ms} ms \
                     (diff={abs_diff} ms, tol={} ms)",
                    opts.datetime_tolerance_ms
                ));
            }
            None
        }

        // ----------------------------------------------------------------
        // Unhandled type combination — surface immediately so new cases are
        // visible rather than being silently skipped.
        // ----------------------------------------------------------------
        _ => Some(format!(
            "col '{col_name}'[{row}] unhandled type combination: \
             ours={our_val:?} (dtype={}), pandas={pd_val:?} (dtype={})",
            our_col.dtype(),
            pd_col.dtype()
        )),
    }
}

/// Compare two DataFrames cell by cell.
///
/// `sas_df` is the output of our SAS7BDAT parser; `pandas_df` is the
/// reference loaded from a pandas-generated Parquet file.
/// `opts` controls comparison tolerances (see `CompareOptions`).
///
/// Returns the complete list of mismatches (empty vec means 100% match).
/// Shape and column-name assertions are hard panics rather than collected
/// mismatches, because any difference there would invalidate all subsequent
/// cell comparisons.
fn compare_dataframes(
    sas_df: &DataFrame,
    pandas_df: &DataFrame,
    file_name: &str,
    opts: CompareOptions,
) -> Vec<String> {
    let mut mismatches = Vec::new();

    // 1. Shape must match ----------------------------------------------------
    assert_eq!(
        sas_df.height(),
        pandas_df.height(),
        "{file_name}: row count mismatch (ours={}, pandas={})",
        sas_df.height(),
        pandas_df.height()
    );
    assert_eq!(
        sas_df.width(),
        pandas_df.width(),
        "{file_name}: column count mismatch (ours={}, pandas={})",
        sas_df.width(),
        pandas_df.width()
    );

    // 2. Column names must match (order-sensitive) ----------------------------
    let our_names: Vec<&str> = sas_df.get_column_names_str();
    let pd_names: Vec<&str> = pandas_df.get_column_names_str();
    assert_eq!(our_names, pd_names, "{file_name}: column name mismatch");

    // 3. Cell-by-cell comparison ---------------------------------------------
    let n_rows = sas_df.height();
    for col_name in &our_names {
        let our_col = sas_df.column(col_name).expect("our column must exist");
        let pd_col = pandas_df
            .column(col_name)
            .expect("pandas column must exist");

        for row in 0..n_rows {
            // Check null alignment first.
            let our_null = our_col.is_null().get(row).expect("is_null index in bounds");
            let pd_null = pd_col.is_null().get(row).expect("is_null index in bounds");

            if our_null != pd_null {
                mismatches.push(format!(
                    "{file_name}: col '{col_name}'[{row}] null mismatch: \
                     ours_is_null={our_null}, pandas_is_null={pd_null}"
                ));
                // Do not attempt value comparison when nullability disagrees.
                continue;
            }

            if our_null {
                // Both null — counts as a match.
                continue;
            }

            // Both non-null: compare values with type normalisation.
            if let Some(msg) = compare_cell(our_col, pd_col, row, col_name, opts) {
                mismatches.push(format!("{file_name}: {msg}"));
            }
        }
    }

    mismatches
}

/// Load the pandas-generated Parquet reference for `name` as a Polars
/// DataFrame, panicking if the file is absent.
fn load_pandas_parquet(name: &str) -> DataFrame {
    let path = expected_dir().join(format!("{name}_pandas.parquet"));
    assert!(
        path.exists(),
        "Reference Parquet not found: {}",
        path.display()
    );
    LazyFrame::scan_parquet(path.to_str().unwrap(), ScanArgsParquet::default())
        .unwrap_or_else(|e| panic!("scan_parquet failed for {name}: {e}"))
        .collect()
        .unwrap_or_else(|e| panic!("collect failed for {name}: {e}"))
}

#[test]
fn exact_match_cars() {
    let sas_path = fixture_path("cars.sas7bdat");
    let (sas_df, _, _, _) = load_sas7bdat_silent(&sas_path).expect("load cars.sas7bdat");
    let pandas_df = load_pandas_parquet("cars");

    let mismatches = compare_dataframes(&sas_df, &pandas_df, "cars", CompareOptions::exact());
    assert!(
        mismatches.is_empty(),
        "cars: {} cell mismatches found:\n{}",
        mismatches.len(),
        mismatches.join("\n")
    );
}

