#[test]
fn exact_match_productsales() {
    // productsales has a MONTH column with MONNAME format stored as a SAS
    // date (days since 1960-01-01).  Our parser emits it as `date` (i32 days
    // since Unix epoch); pandas emits it as `datetime[ms]` at midnight UTC.
    // The Date-vs-Datetime arm in `compare_cell` handles this conversion.
    let sas_path = fixture_path("productsales.sas7bdat");
    let (sas_df, _, _, _) = load_sas7bdat_silent(&sas_path).expect("load productsales.sas7bdat");
    let pandas_df = load_pandas_parquet("productsales");

    let mismatches =
        compare_dataframes(&sas_df, &pandas_df, "productsales", CompareOptions::exact());
    assert!(
        mismatches.is_empty(),
        "productsales: {} cell mismatches found:\n{}",
        mismatches.len(),
        mismatches.join("\n")
    );
}

